import{_ as a,o as s,c as o,ae as t}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Scheduled Log Exports: GCP Storage Expansion","description":"","frontmatter":{"title":"Scheduled Log Exports: GCP Storage Expansion","slug":"scheduled-log-exports-gcp-storage-expansion"},"headers":[],"relativePath":"account-hub/scheduled-log-exports-gcp-storage-expansion.md","filePath":"account-hub/scheduled-log-exports-gcp-storage-expansion.md"}'),n={name:"account-hub/scheduled-log-exports-gcp-storage-expansion.md"};function p(c,e,r,i,u,l){return s(),o("div",null,[...e[0]||(e[0]=[t(`<p>Branch is adding GCP as a cloud service provider you can select when deciding where to send your Scheduled Log Exports API data. 🌩️</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch&#39;s Scheduled Log Exports API lets you schedule daily or hourly exports of your log-level Branch data. You can choose to get an email with this data, store the data in Branch&#39;s AWS S3 buckets, or store the data with your own cloud provider.</p><p>Previously, if you chose to store your data with your own cloud provider, you could only do so with AWS.</p><p>However, Branch is happy to announce that it is now possible to store your data with another one of the industry&#39;s biggest players: GCP!</p><h2 id="api-access" tabindex="-1">API Access <a class="header-anchor" href="#api-access" aria-label="Permalink to &quot;API Access&quot;">​</a></h2><p>Access to the Scheduled Log Exports API is <strong>restricted to Enterprise accounts</strong>. Please contact your Branch Account Manager to confirm if your account is eligible for enablement.</p><h2 id="cloud-configuration" tabindex="-1">Cloud Configuration <a class="header-anchor" href="#cloud-configuration" aria-label="Permalink to &quot;Cloud Configuration&quot;">​</a></h2><p>Before exporting your Branch data to GCP, you will first need to properly configure your cloud account so that the data has a place to land.</p><p>For steps on how to configure your GCP account to work with the Scheduled Log Exports API, view Branch&#39;s <a href="./scheduled-log-exports-cloud-setup.html">cloud setup guide</a>.</p><h2 id="api-usage" tabindex="-1">API Usage <a class="header-anchor" href="#api-usage" aria-label="Permalink to &quot;API Usage&quot;">​</a></h2><p>Pointing the Scheduled Log Exports API to your GCP account happens during the subscription creation call.</p><p>A subscription is a single report (which includes information such as data source, fields, and filters) that is set up to be exported over and over at a regular cadence.</p><p>To create a subscription, <a href="./scheduled-log-exports-api.html#create-new-subscription">send a POST request</a> to the <code>/scheduled-exports/logs/subscribe</code> endpoint.</p><p>Make sure to set <code>destination.subscription_type</code> to <code>cloud</code> and <code>destination.cloud</code> to <code>gcs</code>.</p><p>You will also need to set:</p><ol><li><code>destination.resource_access_id</code>: the full service account name, which looks like an email address<br> For example: <code>branch-sle-service-acct@your-sle-project.iam.gserviceaccount.com</code></li><li><code>destination.bucket</code>: the name of the GCP bucket<br> For <code>/buckets/my-branch-bucket/objects/branch/important_reports/</code> this would be <code>my-branch-bucket</code></li><li><code>destination.prefix</code>: the prefix path for the bucket<br> For <code>/buckets/my-branch-bucket/objects/branch/important_reports/</code> this would be <code>branch/important_reports</code></li></ol><h4 id="example-subscription-creation-request" tabindex="-1">Example Subscription Creation Request <a class="header-anchor" href="#example-subscription-creation-request" aria-label="Permalink to &quot;Example Subscription Creation Request&quot;">​</a></h4><p>This example sets the data export&#39;s destination to GCP:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl -X POST -H &#39;Content-Type: application/json&#39; -H &#39;Accept: application/json&#39; \\</span></span>
<span class="line"><span>-H &#39;access-token: api_app_99999999999999999999999999999999&#39; -d &#39;{</span></span>
<span class="line"><span>  &quot;report&quot;: {</span></span>
<span class="line"><span>    &quot;cadence&quot;: &quot;hourly&quot;,</span></span>
<span class="line"><span>    &quot;response_format&quot;: &quot;csv&quot;,</span></span>
<span class="line"><span>    &quot;response_format_compression&quot;: &quot;gz&quot;,</span></span>
<span class="line"><span>    &quot;report_type&quot;: &quot;eo_install&quot;,</span></span>
<span class="line"><span>    &quot;report_fields&quot;: [</span></span>
<span class="line"><span>      &quot;id&quot;,</span></span>
<span class="line"><span>      &quot;timestamp&quot;,</span></span>
<span class="line"><span>      &quot;user_data_os&quot;,</span></span>
<span class="line"><span>      &quot;user_data_idfa&quot;,</span></span>
<span class="line"><span>      &quot;user_data_aaid&quot;,</span></span>
<span class="line"><span>      &quot;user_data_idfv&quot;</span></span>
<span class="line"><span>    ],</span></span>
<span class="line"><span>    &quot;filter&quot;: [</span></span>
<span class="line"><span>      &quot;eq&quot;,</span></span>
<span class="line"><span>      &quot;attributed&quot;,</span></span>
<span class="line"><span>      &quot;true&quot;</span></span>
<span class="line"><span>    ]</span></span>
<span class="line"><span>  },</span></span>
<span class="line"><span>  &quot;destination&quot;: {</span></span>
<span class="line"><span>    &quot;subscription_type&quot;: &quot;cloud&quot;,</span></span>
<span class="line"><span>    &quot;cloud&quot;: &quot;gcs&quot;,</span></span>
<span class="line"><span>    &quot;resource_access_id&quot;: &quot;branch-sle-service-acct@your-sle-project.iam.gserviceaccount.com&quot;,</span></span>
<span class="line"><span>    &quot;bucket&quot;: &quot;my-branch-bucket&quot;,</span></span>
<span class="line"><span>    &quot;prefix&quot;: &quot;branch/important_reports&quot;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}&#39; &#39;https://api2.branch.io/scheduled-exports/logs/subscribe?app_id=123456789009876543&#39;</span></span></code></pre></div><h2 id="learn-more" tabindex="-1">Learn More <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn More&quot;">​</a></h2><p>For all the details about the Scheduled Log Exports API, visit our reference <a href="./scheduled-log-exports-api.html">guide</a>.</p>`,22)])])}const q=a(n,[["render",p]]);export{h as __pageData,q as default};
